#include<bits/stdc++.h>
using namespace std;
int n,ans=0;
queue <int> q;
struct node
{
    int l,r,lv;
} a[1000005];
void bfs()
{
    q.push(1);
    while(!q.empty())
    {
        if(a[q.front()].l)
        {
            a[a[q.front()].l].lv=a[q.front()].lv+1;
            q.push(a[q.front()].l);
        }
        if(a[q.front()].r)
        {
            a[a[q.front()].r].lv=a[q.front()].lv+1;
            q.push(a[q.front()].r);
        }
        ans=max(ans,a[q.front()].lv);
        q.pop();
    }
}
int main()
{
    cin>>n;
    a[1].lv=1;
    for(int i=1;i<=n;i++)
    {
        int x,y;
        cin>>x>>y;
        a[i].l=x;
        a[i].r=y;
    }
    bfs();
    cout<<ans;
    return 0;
}
